import numpy as np

class Perceptron:
 def __init__(self, learning_rate=0.1, max_iterations=1000):
 self.learning_rate = learning_rate
 self.max_iterations = max_iterations
 self.weights = None
 self.bias = None

 def fit(self, X, y):
 num_samples, num_features = X.shape
 self.weights = np.zeros(num_features)
 self.bias = 0

 for _ in range(self.max_iterations):
 for idx, x_i in enumerate(X):
 linear_output = np.dot(x_i, self.weights) + self.bias
 y_predicted = np.where(linear_output >= 0, 1, -1)

 if y_predicted != y[idx]:
 update = self.learning_rate * y[idx]
 self.weights += update * x_i
 self.bias += update

 def predict(self, X):
 linear_output = np.dot(X, self.weights) + self.bias
 y_predicted = np.where(linear_output >= 0, 1, -1)
 return y_predicted

#include <stdio.h>
#include <stdlib.h>
#include <time.h>

#define MAX_ITERATIONS 1000
#define LEARNING_RATE 0.1

int* perceptron_train(double** X, int* y, int num_samples, int num_features) {
 int* weights = (int*)malloc(num_features * sizeof(int));
 int bias = 0;

 for (int i = 0; i < num_features; i++) {
 weights[i] = 0;
 }

 for (int iter = 0; iter < MAX_ITERATIONS; iter++) {
 for (int i = 0; i < num_samples; i++) {
 double linear_output = 0;
 for (int j = 0; j < num_features; j++) {
 linear_output += X[i][j] * weights[j];
 }
 linear_output += bias;

 int y_predicted = (linear_output >= 0) ? 1 : -1;

 if (y_predicted != y[i]) {
 int update = LEARNING_RATE * y[i];
 for (int j = 0; j < num_features; j++) {
 weights[j] += update * X[i][j];
 }
 bias += update;
 }
 }
 }

 return weights;
}
